class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def diameter_of_tree(root: TreeNode) -> int:
    best = 0
    def depth(node):
        nonlocal best
        if not node:
            return 0
        lh = depth(node.left)
        rh = depth(node.right)
        if lh + rh > best:
            best = lh + rh
        return 1 + (lh if lh > rh else rh)
    depth(root)
    return best

